// Extract sender email and check if it matches a prospect
const emails = $input.all();
const results = [];

for (const email of emails) {
  const from = email.json.from?.emailAddress?.address || 
               email.json.payload?.headers?.find(h => h.name === 'From')?.value || '';

  // Extract email address from "Name <email@domain.com>" format
  const emailMatch = from.match(/<([^>]+)>/) || [null, from];
  const senderEmail = emailMatch[1]?.toLowerCase() || from.toLowerCase();

  // Extract domain for matching
  const domain = senderEmail.split('@')[1] || '';

  // Get subject and snippet
  const subject = email.json.subject || 
                  email.json.payload?.headers?.find(h => h.name === 'Subject')?.value || '';
  const snippet = email.json.snippet || '';
  const body = email.json.text || email.json.snippet || '';

  results.push({
    messageId: email.json.id,
    threadId: email.json.threadId,
    senderEmail: senderEmail,
    senderDomain: domain,
    subject: subject,
    snippet: snippet,
    body: body,
    receivedAt: email.json.internalDate || new Date().toISOString()
  });
}

return results.map(r => ({ json: r }));

// Score the reply intent
const emailData = $('Extract Sender Info').item.json;
const prospect = $input.first().json;

const body = (emailData.body || emailData.snippet || '').toLowerCase();
const subject = (emailData.subject || '').toLowerCase();

// Intent scoring
let intentScore = 50; // Neutral baseline
const signals = [];

// Positive signals (interested)
const positivePatterns = [
  { pattern: /interested/i, score: 30, signal: 'expressed_interest' },
  { pattern: /tell me more/i, score: 25, signal: 'wants_info' },
  { pattern: /sounds good/i, score: 25, signal: 'positive_response' },
  { pattern: /let'?s (talk|chat|meet|connect)/i, score: 35, signal: 'wants_meeting' },
  { pattern: /schedule|calendar|availability/i, score: 35, signal: 'ready_to_book' },
  { pattern: /how much|pricing|cost/i, score: 30, signal: 'pricing_interest' },
  { pattern: /demo/i, score: 35, signal: 'wants_demo' },
  { pattern: /yes/i, score: 20, signal: 'affirmative' },
  { pattern: /call me/i, score: 30, signal: 'wants_call' },
  { pattern: /send.*info|more details/i, score: 25, signal: 'wants_details' }
];

// Negative signals (not interested)
const negativePatterns = [
  { pattern: /not interested/i, score: -40, signal: 'declined' },
  { pattern: /unsubscribe|remove|stop/i, score: -50, signal: 'unsubscribe' },
  { pattern: /no thanks|no thank you/i, score: -35, signal: 'polite_decline' },
  { pattern: /don'?t contact/i, score: -50, signal: 'do_not_contact' },
  { pattern: /already have|already using/i, score: -20, signal: 'has_solution' },
  { pattern: /not a good time|busy/i, score: -10, signal: 'timing_issue' },
  { pattern: /spam/i, score: -50, signal: 'marked_spam' }
];

// Apply patterns
positivePatterns.forEach(p => {
  if (p.pattern.test(body) || p.pattern.test(subject)) {
    intentScore += p.score;
    signals.push(p.signal);
  }
});

negativePatterns.forEach(p => {
  if (p.pattern.test(body) || p.pattern.test(subject)) {
    intentScore += p.score;
    signals.push(p.signal);
  }
});

// Determine lead status
let leadStatus = 'Replied';
let priority = 'medium';
let action = 'review';

if (intentScore >= 80) {
  leadStatus = 'Hot Lead';
  priority = 'urgent';
  action = 'book_meeting';
} else if (intentScore >= 60) {
  leadStatus = 'Warm Lead';
  priority = 'high';
  action = 'follow_up_call';
} else if (intentScore >= 40) {
  leadStatus = 'Interested';
  priority = 'medium';
  action = 'send_more_info';
} else if (intentScore <= 20) {
  leadStatus = 'Not Interested';
  priority = 'low';
  action = 'archive';
} else if (signals.includes('unsubscribe') || signals.includes('do_not_contact')) {
  leadStatus = 'Do Not Contact';
  priority = 'none';
  action = 'remove';
}

return {
  json: {
    // Email data
    messageId: emailData.messageId,
    threadId: emailData.threadId,
    senderEmail: emailData.senderEmail,
    subject: emailData.subject,
    snippet: emailData.snippet,
    body: emailData.body,

    // Prospect data
    prospectId: prospect.id,
    companyName: prospect.fields['Company Name'],
    phone: prospect.fields['Phone'],

    // Scoring
    intentScore: Math.max(0, Math.min(100, intentScore)),
    signals: signals,
    leadStatus: leadStatus,
    priority: priority,
    recommendedAction: action,

    // Meta
    scoredAt: new Date().toISOString()
  }
};

